    (14, 'newTrewe', '', 0, '1770038332247', '', '', '', '3306', 0, 0, '[]', '[]', '[]', 'рҹ“Ғ public/\r\nв””в”Җв”Җ рҹ“Ӯ assets/\r\n    в”ңв”Җв”Җ рҹ“Ӯ css/\r\n    в”Ӯ   в”ңв”Җв”Җ рҹҺЁ common.css\r\n    в”Ӯ   в””в”Җв”Җ рҹҺЁ platform-3d.css\r\n    в””в”Җв”Җ рҹ“Ӯ js/\r\n        в”ңв”Җв”Җ рҹ“Ӯ platform-3d/\r\n        в”Ӯ   в”ңв”Җв”Җ рҹ“ң controls.js\r\n        в”Ӯ   в”ңв”Җв”Җ рҹ“ң exporters.js\r\n        в”Ӯ   в”ңв”Җв”Җ рҹ“ң gizmos.js\r\n        в”Ӯ   в”ңв”Җв”Җ рҹ“ң loaders.js\r\n        в”Ӯ   в””в”Җв”Җ рҹ“ң scene.js\r\n        в””в”Җв”Җ рҹ“ң common.js\r\n\r\nрҹ“Ғ storage/\r\nв”ңв”Җв”Җ рҹ“Ӯ cache/\r\nв””в”Җв”Җ рҹ“Ӯ logs/\r\n\r\nрҹ“Ғ src/\r\nв”ңв”Җв”Җ рҹ“Ӯ Core/\r\nв”Ӯ   в”ңв”Җв”Җ рҹ“Ӯ Auth/\r\nв”Ӯ   в”Ӯ   в””в”Җв”Җ рҹҗҳ AuthService.php\r\nв”Ӯ   в”ңв”Җв”Җ рҹ“Ӯ Database/\r\nв”Ӯ   в”Ӯ   в””в”Җв”Җ рҹҗҳ Connection.php\r\nв”Ӯ   в”ңв”Җв”Җ рҹ“Ӯ Http/\r\nв”Ӯ   в”Ӯ   в”ңв”Җв”Җ рҹҗҳ Request.php\r\nв”Ӯ   в”Ӯ   в””в”Җв”Җ рҹҗҳ Response.php\r\nв”Ӯ   в””в”Җв”Җ рҹ“Ӯ Utils/\r\nв”Ӯ       в”ңв”Җв”Җ рҹҗҳ FileHandler.php\r\nв”Ӯ       в””в”Җв”Җ рҹҗҳ Validator.php\r\nв”ңв”Җв”Җ рҹ“Ӯ Modules/\r\nв”Ӯ   в”ңв”Җв”Җ рҹ“Ӯ Dashboard/\r\nв”Ӯ   в”Ӯ   в””в”Җв”Җ рҹҗҳ DatabaseService.php\r\nв”Ӯ   в””в”Җв”Җ рҹ“Ӯ PromptManager/\r\nв”Ӯ       в””в”Җв”Җ рҹҗҳ PromptService.php\r\nв””в”Җв”Җ рҹҗҳ bootstrap.php\r\n\r\nрҹ“Ғ templates/\r\nв”ңв”Җв”Җ рҹ“Ӯ layouts/\r\nв”Ӯ   в””в”Җв”Җ рҹҗҳ main.php\r\nв””в”Җв”Җ рҹ“Ӯ partials/\r\n    в””в”Җв”Җ рҹҗҳ login-form.php', '{\"language\":\"english\",\"defaultLanguage\":\"english\",\"multiLanguages\":[]}', '[{\"name\":\"public\",\"path\":\"C:/laragon/Prompt-Manager/public\",\"treeText\":\"рҹ“Ғ public/\\nв””в”Җв”Җ рҹ“Ӯ assets/\\n    в”ңв”Җв”Җ рҹ“Ӯ css/\\n    в”Ӯ   в”ңв”Җв”Җ рҹҺЁ common.css\\n    в”Ӯ   в””в”Җв”Җ рҹҺЁ platform-3d.css\\n    в””в”Җв”Җ рҹ“Ӯ js/\\n        в”ңв”Җв”Җ рҹ“Ӯ platform-3d/\\n        в”Ӯ   в”ңв”Җв”Җ рҹ“ң controls.js\\n        в”Ӯ   в”ңв”Җв”Җ рҹ“ң exporters.js\\n        в”Ӯ   в”ңв”Җв”Җ рҹ“ң gizmos.js\\n        в”Ӯ   в”ңв”Җв”Җ рҹ“ң loaders.js\\n        в”Ӯ   в””в”Җ