er\",\"children\":[{\"name\":\"Request.php\",\"type\":\"file\"},{\"name\":\"Response.php\",\"type\":\"file\"}]},{\"name\":\"Utils\",\"type\":\"folder\",\"children\":[{\"name\":\"FileHandler.php\",\"type\":\"file\"},{\"name\":\"Validator.php\",\"type\":\"file\"}]}]},{\"name\":\"Modules\",\"type\":\"folder\",\"children\":[{\"name\":\"Dashboard\",\"type\":\"folder\",\"children\":[{\"name\":\"DatabaseService.php\",\"type\":\"file\"}]},{\"name\":\"PromptManager\",\"type\":\"folder\",\"children\":[{\"name\":\"PromptService.php\",\"type\":\"file\"}]}]},{\"name\":\"bootstrap.php\",\"type\":\"file\"}],\"added\":1771105480662},{\"name\":\"templates\",\"path\":\"C:/laragon/Prompt-Manager/templates\",\"treeText\":\"рҹ“Ғ templates/\\nв”ңв”Җв”Җ рҹ“Ӯ layouts/\\nв”Ӯ   в””в”Җв”Җ рҹҗҳ main.php\\nв””в”Җв”Җ рҹ“Ӯ partials/\\n    в””в”Җв”Җ рҹҗҳ login-form.php\",\"treeData\":[{\"name\":\"layouts\",\"type\":\"folder\",\"children\":[{\"name\":\"main.php\",\"type\":\"file\"}]},{\"name\":\"partials\",\"type\":\"folder\",\"children\":[{\"name\":\"login-form.php\",\"type\":\"file\"}]}],\"added\":1771105480662}]', 'Now I want you to add a checkbox next to the database container next to the left side of the drop down of the database selection drop down box. this checkbox whenever I click it it will send all the tables into the folder template the same way you have created the template in a tree it will send all the tables descending according to the relation of the tables try to do a good educated guess and figure out the relation and it will send the database tables in a relational tree with the same functionality of the template that is sent by the folder picker. So I can drag, drop, add new and all that stuff. So again, I\'ll repeat, do the exact same folder and file tree inside the project folders template, but for the database, try to find a way or an educated guest to find the relations between the main tables and the sub tables. put them in a tree, the main node of the tree should be the database. And all tables should be under the database as children descending according to their logical algorithm or sequence. ', '2026-02-14 21:44:43', '2026-02-14 22:09:27');

